#Connect to all landsat data for 2022
dataset = ee.ImageCollection('LANDSAT/LC08/C02/T1_L2').filterDate(
    '2022-01-01', '2022-12-31'
)

# Mount Google Drive and set an output folder for saving figures,
from pathlib import Path
from google.colab import drive
drive.mount('/content/drive')

# Preprocessing function
def preprocess_landsat8(image):
    # QA masks
    qa_mask = image.select('QA_PIXEL').bitwiseAnd(int('11111', 2)).eq(0)
    saturation_mask = image.select('QA_RADSAT').eq(0)

    # Apply scaling factors
    optical = image.select('SR_B.*').multiply(0.0000275).add(-0.2)
    thermal = image.select('ST_B.*').multiply(0.00341802).add(149.0)

    return (
        image
        .addBands(optical, None, True)
        .addBands(thermal, None, True)
        .updateMask(qa_mask)
        .updateMask(saturation_mask)
    )

dataset_cleaned = dataset.map(preprocess_landsat8)

dataset_sb = dataset_cleaned.mean()

# Print output
print("Number of images in cleaned dataset:")
print(dataset_cleaned.size().getInfo())
print("Bands in mean image:")
print(dataset_sb.bandNames().getInfo())

"""## Task 2: Data Prep"""

csv_path = '/content/drive/My Drive/FORS351/'
csv_file = csv_path + 'training_points.csv'

training_points = pd.read_csv(csv_file)

print(training_points)

# Convert each row to an ee.Feature
def row_to_feature(row):
    return ee.Feature(
        ee.Geometry.Point([row['lon'], row['lat']]),
        {'landcover': row['landcover']}
    )

features = training_points.apply(row_to_feature, axis=1).tolist()

training_points_ee = ee.FeatureCollection(features)

Map = geemap.Map()
Map.addLayer(training_points_ee)
Map.centerObject(training_points_ee, 10)
Map

# Select bands for classifier
bands = ['SR_B2', 'SR_B3', 'SR_B4', 'SR_B5', 'SR_B6', 'SR_B7', 'ST_B10']
image_to_classify = dataset_sb.select(bands)

"""## Training and Testing a Random Forest Classifier"""

# Label our classes
class_labels = {
    0: 'Grassland',
    1: 'Industrial',
    2: 'Park',
    3: 'Residential',
    4: 'Scrub',
    5: 'Water',
    6: 'Wetland'
}

"""## Task 3: Training a random forest classifier"""

def run_tree_classifier(num_trees):
  from sklearn.metrics import confusion_matrix, ConfusionMatrixDisplay
  import numpy as np

  # ------------------------------ TRAIN CLASSIFIER -------------------------- #

  # Sample image at labeled points
  samples = image_to_classify.sampleRegions(
      collection=training_points_ee,
      properties=['landcover'],
      scale=30,
      geometries = True)

  # Split into training and testing
  sample = samples.randomColumn()
  training = sample.filter('random <= 0.7')
  testing = sample.filter('random > 0.7')
  # a 70/30 train test set was chosen because the dataset is small/moderate
  # and this will enable us to have sufficient test data without overfitting

  # Train Random Forest classifier
  classifier = ee.Classifier.smileRandomForest(num_trees).train(
      features=training,
      classProperty='landcover',
      inputProperties=bands
  )

  # ------------------- TEST CLASSIFIER ---------------------- #

  # Validate on withheld data
  validation_sample = testing.classify(classifier)

  # Confusion matrix and accuracy
  test_accuracy = validation_sample.errorMatrix('landcover', 'classification')

  cm = np.array(test_accuracy.getInfo())
  print('Confusion Matrix:', cm)
  print('Overall Accuracy:', test_accuracy.accuracy().getInfo())

  labels_ordered = [class_labels[i] for i in range(len(class_labels))]
  disp = ConfusionMatrixDisplay(confusion_matrix=cm,display_labels=labels_ordered)
  disp.plot(xticks_rotation = 45)

# 50 Trees
run_tree_classifier(50)

# 10 Trees
run_tree_classifier(10)

# 100 Trees
run_tree_classifier(100)

# 75 Trees
run_tree_classifier(75)

